var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"어머니는 잘 보내드렸나?","JPN":"お母様は無事に送ってあげられたのか？","ENG":"Did you say goodbye to your mother?","TWN":"有好好送媽媽嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"……네, 주인어른.","JPN":"……はい、社長。","ENG":"Yes, Master.","TWN":"……是，主人。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"제 어머니에 대한 진실을 알고 싶다면 연합으로 돌아가라고 하셨죠.","JPN":"私の母についての真実を知りたければ、連合に戻るようにとおっしゃいましたね。","ENG":"You told me to go back to the Alliance if I wanted to know what really happened to my mother.","TWN":"你曾說過，如果想知道關於家母的真相，就要回到聯盟。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"주인어른께선, 이미 모든 진실을 알고 계셨던 건가요?","JPN":"社長は最初からすべての真実を知っていたのですか？","ENG":"Did you know all this already?","TWN":"主人已經知道全部的真相嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아니? 나라고 자네가 생각하는 것처럼 모든 것을 알지는 못한다네.","JPN":"いや、私でも君が思うほどすべてを知ることができるわけじゃない。","ENG":"No. I am not omnipotent.","TWN":"不，我並非如你所想的那般無所不知。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그저, 다른 이들보다 진실을 들춰볼 기회가 좀 더 많았을 뿐이야.","JPN":"ただ、他の人より真実を暴く機会が多かっただけさ。","ENG":"However, I do have more opportunities to find fragments of truth than others.","TWN":"我只是比其他人多一點機會揭露真相而已。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"하지만 제가 개입함으로써 실패의 인과가 뒤바뀔 수 있다는 건 알고 계셨던 거겠죠.","JPN":"しかし、私が介入することで\\n失敗の因果が逆転する可能性があることもご存知だったのでしょう。","ENG":"But you must have known that sending me back to the Alliance would change the outcome.","TWN":"但是你應該知道因為我的介入，失敗的因果很可能會發生變化吧？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"정해진 미래라는 것은 없어.","JPN":"決められた未来というものはない。","ENG":"The future is not set.","TWN":"沒有註定的未來。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네의 존재. 그리고 어릴 적 만났던 소년과 소녀. 그리고 사공 가문의 자손.","JPN":"君の存在。そして幼い頃に出会った少年と少女。そして船頭の一族の子孫。","ENG":"You, a girl and a boy who met when they were young, and a descendant of ship navigators.","TWN":"你的存在，還有小時候遇到的男孩和女孩，以及香取的後代。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이 모든 이들이 만들어낸 변화의 인과라네.","JPN":"このすべての者が作り出した変化の因果だ。","ENG":"Everyone who was there was the element of change.","TWN":"都是他們創造出的變化因果。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그 뒤에는…… 좋은 결과가 있기만을 바랄 뿐이지.","JPN":"その後は……良い結果となることを願うだけさ。","ENG":"Once everything was set... all I could do was to pray for good news.","TWN":"在那之後… 只希望會有好結果。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"음? 이건……?","JPN":"うん？　これは……？","ENG":"Oh? What is this?","TWN":"嗯？這是……？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"신사에서 제공하는 오미쿠지로군요.","JPN":"神社が提供しているおみくじですね。","ENG":"It’s omikuji from a shrine.","TWN":"原來是神社提供的御神籤。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"하나 뽑아보시겠습니까?","JPN":"一度引いてみませんか？","ENG":"Would you like to pick one?","TWN":"您要抽抽看嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"……이건?!","JPN":"……これは！？","ENG":"Huh?","TWN":"……這是？！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"대흉을 뽑으셨군요.","JPN":"大凶を引かれたのですね。","ENG":"You picked “Great Curse”.","TWN":"您抽到的是大凶。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"이런 기분 나쁠 수 있는 결과는 일부러 적게 섞는다고 알고 있습니다만.","JPN":"こういった良くない結果はあえて少なくしていると聞いていますが。","ENG":"I thought they didn’t put misfortunes in the box because it might offend people.","TWN":"不過這裡面應該很少這種會讓人心情不好的籤。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"뭐…… 이렇듯, 미래라는 건 아무도 알 수 없는 걸세.","JPN":"まあ……このように、未来というのは誰にもわからないんだ。","ENG":"Well, I guess this is the proof that no one can tell the future.","TWN":"嗯… 就像這樣，未來的事誰也不知道。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네의 앞날도, 내 앞날도.","JPN":"君の行く末も、私の行く末も。","ENG":"Not yours nor mine.","TWN":"不管是你的未來或是我的未來。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"결국 헤쳐나가기 전까진 어떻게 될지 모르는 법이지.","JPN":"結局、乗り越えるまでどうなるかわからないものだ。","ENG":"You don’t know what will happen until it actually happens.","TWN":"不到最後一刻，都不知道會怎麼樣。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"……그렇군요.","JPN":"……そうですね。","ENG":"I see.","TWN":"……原來如此。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"마침 연합의 회동 중에 쓰이는 찻잎을 입수했습니다만, 목을 축이고 가시련지요.","JPN":"ちょうど連合の会合に出す茶葉を入手したのですが、\\n喉を潤して行かれますか？","ENG":"I brought some good tea leaves from the Alliance. Would you like to try some?","TWN":"剛好有聯盟聚會時使用的茶葉，潤潤喉再走吧。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그런 제안이라면 거절할 수가 없지. 부사장에게도 얘기해 둬야겠군.","JPN":"そういう提案なら断れないな。副社長にも話しておかないと。","ENG":"I won’t refuse such a kind offer. I’ll tell the Vice President.","TWN":"這種提議我當然無法拒絕囉！我先跟副總説一下。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그리고 이것 보게나. 대흉은커녕 대길이지 않나.","JPN":"あと、ほら。大凶どころか大吉じゃないか。","ENG":"Look, who would say it’s a Great Curse? It’s rather a Great Blessing.","TWN":"你看看，哪是什麼大凶，根本是大吉吧？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네가 손수 달여 주는 차도 대접 받고 말이야.","JPN":"君が直接淹れてくれるお茶でもてなしてもらえるんだ。","ENG":"You’re making me a nice cup of tea.","TWN":"我還能喝到你親手泡的茶。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"높이 평가해 주시니 황송할 따름입니다.","JPN":"高く評価していただき恐縮です。","ENG":"Thank you for the compliment.","TWN":"聽你這麼說我反而壓力更大呢。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"그럼, 안으로 드시죠.","JPN":"それでは、中へどうぞ。","ENG":"Please come in.","TWN":"那就裡面請吧。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}}]`);export{e as default};